vol_map = {item['Symbol']: item['AvgVolume'] for item in trade_data}

# Join
results = []
for item in stockinfo:
    sym = item['Symbol']
    if sym in vol_map:
        avg_vol = vol_map[sym]
        if avg_vol != 'nan' and avg_vol is not None:
             # Check if volume > 0? "trading volume in 2008".
             # If avg is > 0, it means there was some volume.
             if float(avg_vol) > 0:
                 results.append({
                     "Company Name": item['Company Description'],
                     "Average Daily Trading Volume": float(avg_vol)
                 })

print("__RESULT__:")
print(json.dumps(results))

