import json

stockinfo = locals()['var_function-call-15144739907481070706']
trade_data = locals()['var_function-call-7347467708157542699']

# Create a lookup for avg volume
vol_map = {item['Symbol']: item['AvgVolume'] for item in trade_data}

# Join
results = []
for item in stockinfo:
    sym = item['Symbol']
    if sym in vol_map:
        avg_vol = vol_map[sym]
        # avg_vol might be the string "nan" or None
        if avg_vol != 'nan' and avg_vol is not None:
             try:
                 val = float(avg_vol)
                 if val > 0:
                     results.append({
                         "Company Name": item['Company Description'],
                         "Average Daily Trading Volume": val
                     })
             except ValueError:
                 continue

print("__RESULT__:")
print(json.dumps(results))

